const incoming = $json || {};
const root =
  incoming.body && typeof incoming.body === 'object' && !Array.isArray(incoming.body)
    ? { ...incoming, ...incoming.body }
    : incoming;
const raw = String(root.ticker ?? '').trim();
const ticker = raw || 'UNKNOWN';
const date = String(root.date ?? '').trim() || new Date().toISOString().slice(0, 10);
const session_id = root.session_id ?? null;
const execution_price = root.execution_price;

function parseCryptoPair(symbol) {
  const s = symbol.toLowerCase().replace(/\s+/g, '');
  const m = /^([a-z0-9]{2,10})[\/-]?usdt$/i.exec(s);
  if (m) return { pair: (m[1] + 'usd').toLowerCase() };
  const m2 = /^([a-z0-9]{2,10})[\/-]?(usd|eur|gbp|jpy)$/i.exec(s);
  if (m2) return { pair: (m2[1] + m2[2]).toLowerCase() };
  if (/^(btc|eth|sol|xrp|doge|ada|bnb|avax)$/i.test(s)) return { pair: s.toLowerCase() + 'usd' };
  return null;
}

function inferMarketFromTicker(sym) {
  const s = String(sym || '').trim();
  if (!s) return 'us';
  const lo = s.toLowerCase();
  if (lo.endsWith('.ns') || lo.endsWith('.bo')) return 'india';
  if (parseCryptoPair(s)) return 'crypto';
  return 'us';
}

let market = String(root.market ?? '').trim().toLowerCase();
if (market !== 'us' && market !== 'india' && market !== 'crypto') {
  market = inferMarketFromTicker(raw);
}

const technical_markers_context = [
  '### Technical bundle (workflow-computed)',
  'US equities (`market=us`): 5-minute IEX bars via Alpaca Market Data v2 (`feed=iex`, free paper tier). Indicators: RSI(14), MACD(12,26,9), EMA(9), EMA(21), ATR(14), VWAP over fetched window, rolling SMA over last 200 closes on that timeframe when available.',
  'India / crypto: Tiingo daily OHLCV; same core indicators on daily closes; SMA(200) when history allows.',
  'See `technical_metrics.timeframe`, `technical_metrics.source`, and numeric fields; do not invent values.'
].join('\n');

function classifySymbol(symbol) {
  if (!symbol || symbol === 'UNKNOWN') {
    return {
      asset_route: 'equity_eod',
      tiingo_equity_ticker: 'UNKNOWN',
      tiingo_crypto_tickers: null,
      symbol_class: 'unknown',
      symbol_routing_note: 'No ticker supplied.'
    };
  }
  const crypto = parseCryptoPair(symbol);
  if (crypto) {
    return {
      asset_route: 'crypto_eod',
      tiingo_equity_ticker: null,
      tiingo_crypto_tickers: crypto.pair,
      symbol_class: 'crypto',
      symbol_routing_note: 'Crypto: Tiingo daily crypto prices.'
    };
  }
  const upper = symbol.toUpperCase();
  if (/\.NS$/i.test(symbol)) {
    return {
      asset_route: 'equity_eod',
      tiingo_equity_ticker: upper,
      tiingo_crypto_tickers: null,
      symbol_class: 'india_nse',
      symbol_routing_note: 'India NSE: Tiingo daily EOD.'
    };
  }
  if (/\.BO$/i.test(symbol)) {
    return {
      asset_route: 'equity_eod',
      tiingo_equity_ticker: upper,
      tiingo_crypto_tickers: null,
      symbol_class: 'india_bse',
      symbol_routing_note: 'India BSE: Tiingo daily EOD.'
    };
  }
  const cleaned = upper.replace(/[^A-Z0-9.-]/g, '');
  return {
    asset_route: 'equity_eod',
    tiingo_equity_ticker: cleaned || upper,
    tiingo_crypto_tickers: null,
    symbol_class: 'us_or_global_equity',
    symbol_routing_note: 'US equity: intraday via Alpaca when market=us; Tiingo daily fallback.'
  };
}

const routed = classifySymbol(raw);
const note = routed.symbol_routing_note + ' Orchestrator market: ' + market + '.';

const end = new Date(date + 'T12:00:00Z');
const start = new Date(end);
start.setUTCDate(start.getUTCDate() - 320);
const fmt = (dt) => dt.toISOString().slice(0, 10);
const tiingo_start_date = fmt(start);
const tiingo_end_date = fmt(end);

function buildQuery(params) {
  const keys = Object.keys(params);
  const out = [];
  for (let i = 0; i < keys.length; i++) {
    const k = keys[i];
    const v = params[k];
    if (v === undefined || v === null) continue;
    out.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
  }
  return out.join('&');
}

let tiingo_full_prices_url = '';
if (routed.asset_route === 'crypto_eod' && routed.tiingo_crypto_tickers) {
  tiingo_full_prices_url = 'https://api.tiingo.com/tiingo/crypto/prices?' + buildQuery({
    tickers: routed.tiingo_crypto_tickers,
    resampleFreq: '1day',
    startDate: tiingo_start_date,
    endDate: tiingo_end_date
  });
} else {
  const pathTicker = encodeURIComponent(routed.tiingo_equity_ticker || 'INVALID');
  tiingo_full_prices_url = 'https://api.tiingo.com/tiingo/daily/' + pathTicker + '/prices?' + buildQuery({ startDate: tiingo_start_date, endDate: tiingo_end_date });
}

let alpaca_bars_url = null;
if (market === 'us' && routed.asset_route === 'equity_eod' && routed.tiingo_equity_ticker && routed.tiingo_equity_ticker !== 'UNKNOWN') {
  const sym = routed.tiingo_equity_ticker;
  const endDt = new Date(date + 'T23:59:59.999Z');
  const startDt = new Date(endDt);
  startDt.setUTCDate(startDt.getUTCDate() - 14);
  const qs =
    'timeframe=5Min&start=' +
    encodeURIComponent(startDt.toISOString()) +
    '&end=' +
    encodeURIComponent(endDt.toISOString()) +
    '&limit=500&feed=iex&sort=asc';
  alpaca_bars_url = 'https://data.alpaca.markets/v2/stocks/' + encodeURIComponent(sym) + '/bars?' + qs;
}

return [{
  json: {
    ticker,
    date,
    session_id,
    execution_price,
    market,
    technical_markers_context,
    asset_route: routed.asset_route,
    symbol_class: routed.symbol_class,
    symbol_routing_note: note,
    tiingo_equity_ticker: routed.tiingo_equity_ticker,
    tiingo_crypto_tickers: routed.tiingo_crypto_tickers,
    tiingo_start_date,
    tiingo_end_date,
    tiingo_full_prices_url,
    alpaca_bars_url
  }
}];

const meta = $('Prepare Technical Context').first().json;
const raw = $input.first().json;
if (raw && raw.error) {
  const e = raw.error;
  const msg = (e && (e.message || e.description)) ? String(e.message || e.description) : JSON.stringify(e);
  return [{ json: { ...meta, technical_metrics: null, technical_metrics_error: 'OHLCV HTTP node error: ' + msg } }];
}
let rows = raw;
if (raw && raw.body !== undefined && raw.body !== null) {
  rows = raw.body;
}

function normalizeCandlesFromTiingo(rawRows) {
  let r = rawRows;
  if (Array.isArray(r) && r.length && r[0] && Array.isArray(r[0].priceData)) {
    r = r[0].priceData;
  }
  if (!Array.isArray(r)) return null;
  return r
    .map((row) => {
      const d = row.date || row.Date;
      const c = row.close !== undefined && row.close !== null ? row.close : (row.adjClose !== undefined ? row.adjClose : row.adj_close);
      return {
        date: d ? String(d).slice(0, 10) : '',
        ts: d ? String(d) : '',
        close: Number(c),
        open: Number(row.open),
        high: Number(row.high),
        low: Number(row.low),
        volume: Number(row.volume) || 0
      };
    })
    .filter((x) => x.date && Number.isFinite(x.close))
    .sort((a, b) => a.date.localeCompare(b.date));
}

function normalizeCandlesFromAlpaca(body) {
  if (!body || !Array.isArray(body.bars)) return null;
  return body.bars
    .map((b) => ({
      date: new Date(b.t).toISOString(),
      ts: new Date(b.t).toISOString(),
      close: Number(b.c),
      open: Number(b.o),
      high: Number(b.h),
      low: Number(b.l),
      volume: Number(b.v) || 0
    }))
    .filter((x) => Number.isFinite(x.close))
    .sort((a, b) => a.ts.localeCompare(b.ts));
}

let candles = normalizeCandlesFromAlpaca(rows);
let timeframe = '5m';
let source = 'alpaca_5m_iex_derived';
function rowsLookTiingo(r) {
  if (!r) return false;
  if (Array.isArray(r) && r.length && typeof r[0] === 'object' && (r[0].date !== undefined || r[0].adjClose !== undefined || r[0].close !== undefined)) return true;
  if (Array.isArray(r) && r.length && r[0] && Array.isArray(r[0].priceData)) return true;
  return false;
}
if ((!candles || candles.length < 10) && rowsLookTiingo(rows)) {
  candles = normalizeCandlesFromTiingo(rows);
  timeframe = '1d';
  source = 'tiingo_ohlcv_derived';
}

if (!candles || candles.length < 10) {
  return [{ json: { ...meta, technical_metrics: null, technical_metrics_error: 'Insufficient OHLCV rows after parse' } }];
}

const closes = candles.map((c) => c.close);
const highs = candles.map((c) => c.high);
const lows = candles.map((c) => c.low);

function computeRSI(closes, period) {
  if (closes.length < period + 1) return null;
  let avgGain = 0;
  let avgLoss = 0;
  for (let i = 1; i <= period; i++) {
    const change = closes[i] - closes[i - 1];
    if (change > 0) avgGain += change;
    else avgLoss -= change;
  }
  avgGain /= period;
  avgLoss /= period;
  for (let i = period + 1; i < closes.length; i++) {
    const change = closes[i] - closes[i - 1];
    const gain = change > 0 ? change : 0;
    const loss = change < 0 ? -change : 0;
    avgGain = (avgGain * (period - 1) + gain) / period;
    avgLoss = (avgLoss * (period - 1) + loss) / period;
  }
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - 100 / (1 + rs);
}

function emaSeries(vals, span) {
  const k = 2 / (span + 1);
  const out = [];
  let e = vals[0];
  out.push(e);
  for (let i = 1; i < vals.length; i++) {
    e = vals[i] * k + e * (1 - k);
    out.push(e);
  }
  return out;
}

function atr14(highs, lows, closes) {
  if (highs.length < 15) return null;
  const trs = [];
  for (let i = 0; i < highs.length; i++) {
    if (i === 0) {
      trs.push(highs[0] - lows[0]);
      continue;
    }
    const hl = highs[i] - lows[i];
    const hc = Math.abs(highs[i] - closes[i - 1]);
    const lc = Math.abs(lows[i] - closes[i - 1]);
    trs.push(Math.max(hl, hc, lc));
  }
  let atr = trs.slice(0, 14).reduce((a, b) => a + b, 0) / 14;
  for (let i = 14; i < trs.length; i++) {
    atr = (atr * 13 + trs[i]) / 14;
  }
  return atr;
}

function vwapWindow(candles) {
  let pv = 0;
  let vol = 0;
  for (const c of candles) {
    const tp = (c.high + c.low + c.close) / 3;
    const v = c.volume || 0;
    pv += tp * v;
    vol += v;
  }
  return vol > 0 ? pv / vol : null;
}

const rsi14 = computeRSI(closes, 14);
const ema12 = emaSeries(closes, 12);
const ema26 = emaSeries(closes, 26);
const macdLine = ema12.map((v, i) => v - ema26[i]);
const macdSignalArr = emaSeries(macdLine, 9);
const last = closes.length - 1;
const macd_line = macdLine[last];
const macd_signal = macdSignalArr[last];
const macd_histogram = macd_line - macd_signal;

const ema9s = emaSeries(closes, 9);
const ema21s = emaSeries(closes, 21);

const win200 = closes.slice(-200);
const sma200 = win200.length >= 200 ? win200.reduce((a, b) => a + b, 0) / 200 : null;

const technical_metrics = {
  timeframe,
  source,
  rsi14: rsi14 != null ? Math.round(rsi14 * 100) / 100 : null,
  macd_line: Math.round(macd_line * 10000) / 10000,
  macd_signal: Math.round(macd_signal * 10000) / 10000,
  macd_histogram: Math.round(macd_histogram * 10000) / 10000,
  ema9: Math.round(ema9s[last] * 10000) / 10000,
  ema21: Math.round(ema21s[last] * 10000) / 10000,
  atr14: atr14(highs, lows, closes) != null ? Math.round(atr14(highs, lows, closes) * 10000) / 10000 : null,
  vwap_window: vwapWindow(candles) != null ? Math.round(vwapWindow(candles) * 10000) / 10000 : null,
  sma200: sma200 != null ? Math.round(sma200 * 10000) / 10000 : null,
  last_close: Math.round(closes[last] * 10000) / 10000,
  as_of: candles[last] ? candles[last].ts || candles[last].date : meta.date,
  bars_used: closes.length
};

return [{ json: { ...meta, technical_metrics } }];

const meta = $('Compute Technical Metrics').first().json;
const agentOutput = $json.output || $json.text || $json.content || '';

// Extract structured signal from SIGNAL_JSON: line
let structuredSignal = null;
const lines = agentOutput.split('\n');
for (const line of lines) {
  const trimmed = line.trim();
  if (trimmed.startsWith('SIGNAL_JSON:')) {
    try {
      structuredSignal = JSON.parse(trimmed.replace('SIGNAL_JSON:', '').trim());
      break;
    } catch (_) {}
  }
}

// Fallback: infer from text sentiment
if (!structuredSignal) {
  const lower = agentOutput.toLowerCase();
  const signal = lower.includes('bullish') ? 'BULLISH' : lower.includes('bearish') ? 'BEARISH' : 'NEUTRAL';
  structuredSignal = { signal, confidence: 'Low' };
}

const tm = meta.technical_metrics || {};
const technical_summary = {
  signal: structuredSignal.signal || 'NEUTRAL',
  confidence: structuredSignal.confidence || 'Low',
  rsi14: structuredSignal.rsi14 ?? tm.rsi14 ?? null,
  macd_histogram: structuredSignal.macd_histogram ?? tm.macd_histogram ?? null,
  ema9: tm.ema9 ?? null,
  ema21: tm.ema21 ?? null,
  sma200: tm.sma200 ?? null,
  atr14: tm.atr14 ?? null,
  last_close: tm.last_close ?? null,
  timeframe: tm.timeframe || '1d',
  source: tm.source || 'unknown',
  bars_used: tm.bars_used ?? null,
  ema_trend: structuredSignal.ema_trend ?? ((tm.ema9 && tm.ema21) ? (tm.ema9 > tm.ema21 ? 'above' : 'below') : 'flat')
};

// Strip the SIGNAL_JSON line from prose output
const cleanOutput = lines.filter(l => !l.trim().startsWith('SIGNAL_JSON:')).join('\n').trim();

return [{ json: {
  output: cleanOutput + '\n\nTECHNICAL_SUMMARY: ' + JSON.stringify(technical_summary),
  technical_summary,
  ticker: meta.ticker,
  date: meta.date,
  session_id: meta.session_id,
  market: meta.market
} }];
